// This shopping cart has 3 bugs. Find and fix them!

export interface CartItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
}

export class ShoppingCart {
  private items: CartItem[] = [];

  addItem(item: CartItem): void {
    const existing = this.items.find(i => i.id = item.id); // BUG 1: Assignment instead of comparison
    if (existing) {
      existing.quantity += item.quantity;
    } else {
      this.items.push(item);
    }
  }

  removeItem(id: string): boolean {
    const index = this.items.findIndex(i => i.id === id);
    if (index >= 0) {
      this.items.splice(index); // BUG 2: Missing second argument (delete count)
      return true;
    }
    return false;
  }

  getTotal(): number {
    return this.items.reduce((sum, item) => {
      return sum + item.price * item.quantity; // BUG 3: Should round to avoid floating point issues
    }, 0);
  }

  getItemCount(): number {
    return this.items.reduce((count, item) => count + item.quantity, 0);
  }

  clear(): void {
    this.items = [];
  }

  getItems(): CartItem[] {
    return [...this.items];
  }
}

