import { ShoppingCart } from './shopping-cart';

const cart = new ShoppingCart();

// Test 1: Add item
cart.addItem({ id: '1', name: 'Apple', price: 1.99, quantity: 2 });
const items = cart.getItems();
if (items.length !== 1) throw new Error('Should have 1 item');
if (items[0].quantity !== 2) throw new Error('Should have quantity 2');

// Test 2: Add same item again (should merge)
cart.addItem({ id: '1', name: 'Apple', price: 1.99, quantity: 3 });
const items2 = cart.getItems();
if (items2.length !== 1) throw new Error('Should still have 1 item');
if (items2[0].quantity !== 5) throw new Error('Should have quantity 5');

// Test 3: Remove item
cart.removeItem('1');
if (cart.getItems().length !== 0) throw new Error('Should have 0 items');

// Test 4: Total calculation
cart.clear();
cart.addItem({ id: '1', name: 'Item', price: 0.1, quantity: 3 });
const total = cart.getTotal();
if (Math.abs(total - 0.3) > 0.01) throw new Error(`Total should be 0.30, got ${total}`);

console.log('All tests passed!');
